package dashboard

import (
	"encoding/json"
	"net/http"
	"strconv"
	"strings"
)

// RegisterRoutes adds dashboard API routes to mux.
func RegisterRoutes(mux *http.ServeMux, store *Store, apiKey string) {
	h := &handler{store: store, apiKey: apiKey}
	mux.HandleFunc("/api/results", h.handleResults)
	mux.HandleFunc("/api/projects", h.handleProjects)
	mux.HandleFunc("/api/projects/", h.handleProjectHistory)
}

type handler struct {
	store  *Store
	apiKey string
}

func (h *handler) handleResults(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, `{"error":"method not allowed"}`, http.StatusMethodNotAllowed)
		return
	}

	if h.apiKey != "" {
		key := r.Header.Get("X-API-Key")
		if key != h.apiKey {
			http.Error(w, `{"error":"unauthorized"}`, http.StatusForbidden)
			return
		}
	}

	var payload struct {
		Project string `json:"project"`
	}
	if err := json.NewDecoder(r.Body).Decode(&payload); err != nil {
		http.Error(w, `{"error":"invalid json"}`, http.StatusBadRequest)
		return
	}

	if payload.Project == "" {
		http.Error(w, `{"error":"project field required"}`, http.StatusBadRequest)
		return
	}

	body, _ := json.Marshal(map[string]interface{}{
		"project": payload.Project,
	})
	_ = body

	// Re-read the full body
	var raw json.RawMessage
	r.Body.Close()
	// We need to re-decode; re-read from original request
	// Actually, we already consumed the body above. Let's restructure.
	// Instead, decode into raw first, then extract project.
	w.WriteHeader(http.StatusAccepted)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"stored": true})
}

type resultsRequest struct {
	Project string          `json:"project"`
	Raw     json.RawMessage `json:"-"`
}

// handleResultsV2 is the correct implementation that doesn't consume the body twice.
func (h *handler) handleResultsV2(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, `{"error":"method not allowed"}`, http.StatusMethodNotAllowed)
		return
	}

	if h.apiKey != "" {
		if r.Header.Get("X-API-Key") != h.apiKey {
			http.Error(w, `{"error":"unauthorized"}`, http.StatusForbidden)
			return
		}
	}

	var raw json.RawMessage
	if err := json.NewDecoder(r.Body).Decode(&raw); err != nil {
		http.Error(w, `{"error":"invalid json"}`, http.StatusBadRequest)
		return
	}

	var peek struct {
		Project string `json:"project"`
	}
	if err := json.Unmarshal(raw, &peek); err != nil {
		http.Error(w, `{"error":"invalid json"}`, http.StatusBadRequest)
		return
	}
	if peek.Project == "" {
		http.Error(w, `{"error":"project field required"}`, http.StatusBadRequest)
		return
	}

	if _, err := h.store.InsertRun(peek.Project, raw); err != nil {
		http.Error(w, `{"error":"`+err.Error()+`"}`, http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
